290	    if (!line.startsWith("- ")) continue;
291	    if (line.includes("[初稿]") || line.includes("最近5条消息摘要")) continue;
292	    const m = line.match(chatRe);
293	    if (m) {
294	      lines.push({
295	        who: m[2] === "我" ? "me" : "cust",
296	        time: m[1].slice(5), // MM-DD
297	        text: m[3].trim().substring(0, 150),
298	      });
299	    } else {
300	      // 宽松匹配
301	      const loose = line.match(/^-\s*(\d{4}-\d{2}-\d{2})\s+(.+)$/);
302	      if (loose) {
303	        const rest = loose[2];
304	        const whoStr = rest.startsWith("我") ? "me" : rest.startsWith("客") ? "cust" : null;
305	        if (whoStr) {
306	          const text = rest.replace(/^[我客](?:催单|告知|跟进|回复|追问|)?[：:]?\s*/, "").replace(/（MsgID:[\w.]+）$/, "").trim();
307	          lines.push({ who: whoStr, time: loose[1].slice(5), text: text.substring(0, 150) });
308	        }
309	      }
310	    }
311	  }
312	  return lines.slice(-6); // 最近6条
313	}
