315	/** 将英文聊天行转为中文叙事摘要 */
316	function chatToChinese(chatLines) {
317	  if (!chatLines || chatLines.length === 0) return [];
318	  return chatLines.map(cl => {
319	    const who = cl.who === 'me' ? '我方' : '客户';
320	    const text = (cl.text || '').trim();
321	    // 识别关键动作
322	    let action = text;
323	    const lower = text.toLowerCase();
324	    if (/sent.*(pic|photo|image|picture)/i.test(lower)) action = '发来图片';
325	    else if (/^ok(ay)?$/i.test(lower) || /^(yes|yeah|sure|good|great|thanks|thank|👍)/i.test(lower)) action = '确认';
326	    else if (/create.*order|send.*(order|payment|link|PI|invoice)/i.test(lower)) action = '发送订单/付款链接';
327	    else if (/arrange.*ship|will.*ship|shipping/i.test(lower)) action = '说明物流安排';
328	    else if (/ready|prepared|备好/i.test(lower)) action = '告知备货完成';
329	    else if (/quote|报价|price.*USD|USD.*price|\$\d/i.test(lower)) action = '报价：' + text.substring(0, 60);
330	    else if (/\?$/.test(text.trim())) action = '询问：' + text.substring(0, 50);
331	    else if (text.length > 80) action = text.substring(0, 70) + '…';
332	    return { who, time: cl.time, action };
333	  });
334	}
