336	function extractKeyNums(content) {
337	  const section = extractSection(content, "关键数字");
338	  if (!section) return [];
339	  return section.split("\n")
340	    .filter(l => l.trim().startsWith("-") && !l.includes("[初稿]"))
341	    .map(l => l.replace(/^-\s*/, "").trim())
342	    .filter(Boolean);
343	}
