345	function extractNextStep(content) {
346	  const section = extractSection(content, "下一步");
347	  const lines = section.split("\n").filter(l => l.trim().startsWith("→"));
348	  if (lines.length > 0) {
349	    return lines.map(l => l.replace(/^→\s*(?:\[初稿\]\s*)?/, "").trim()).join("\n");
350	  }
351	  return section.replace(/^→\s*(?:\[初稿\]\s*)?/, "").trim().substring(0, 120);
352	}
