354	function loadBriefs() {
355	  const map = {};
356	  if (!fs.existsSync(BRIEFS_DIR)) return map;
357	  for (const file of fs.readdirSync(BRIEFS_DIR)) {
358	    if (!file.endsWith(".md")) continue;
359	    const content = fs.readFileSync(path.join(BRIEFS_DIR, file), "utf-8");
360	    const fm = parseFrontmatter(content);
361	    if (fm.cid) map[fm.cid] = { frontmatter: fm, content, file };
362	  }
363	  return map;
364	}
