378	    return null;
379	  }
380	
381	  const factorMap = new Map();
382	  if (soon) for (const c of soon.customers || []) factorMap.set(c.cid, c);
383	
384	  const coldCids = new Set();
385	  if (cold) {
386	    for (const layer of Object.values(cold.frozen || {})) {
387	      for (const c of layer) coldCids.add(c.cid);
388	    }
389	  }
390	
391	  const cards = [];
392	
393	  for (const [cid, data] of Object.entries(baselines)) {
394	    const stage = data.stage || "未知";
395	    const soonData = factorMap.get(cid);
396	    const factors = soonData ? soonData.factors : [];
397	    const brief = briefs[cid];
398	    const briefHeat = (brief && brief.frontmatter && brief.frontmatter.heat) || null;
399	    const urgencyKey = coldCids.has(cid) ? "frozen" : classifyUrgency(factors, briefHeat);
400	    const tier = (data.meta && data.meta.customer_tier) || "C";
401	    const paymentConfirmed = (data.meta && data.meta._payment_confirmed) || false;
402	    const orderStatus = (data.meta && data.meta._order_status) || null;
403	
404	    let daysSince = null, lastContactDate = null, firstContact = null;
405	    if (data.baselines) {
406	      let latest = null, earliest = null;
407	      for (const v of Object.values(data.baselines)) {
408	        if (v) {
409	          if (!latest || v > latest) latest = v;
410	          if (!earliest || v < earliest) earliest = v;
411	        }
412	      }
413	      if (latest) { lastContactDate = latest; daysSince = Math.floor((new Date(TODAY) - new Date(latest)) / 86400000); }
414	      firstContact = earliest;
415	    }
416	
417	    let chatLines = [], chatLinesCN = [], keyNums = [], nextStep = "";
418	
419	    // 服务端生成富驱动因子描述
420	    const richDrivers = factors.length > 0
421	      ? buildRichDrivers(factors, stage, daysSince, paymentConfirmed, brief ? brief.content : null)
422	      : [];
423	
424	    if (brief) {
425	      chatLines = extractChatLines(brief.content);
426	      chatLinesCN = chatToChinese(chatLines);
427	      keyNums = extractKeyNums(brief.content);
428	      nextStep = extractNextStep(brief.content);
429	    }
430	
431	    cards.push({
432	      cid,
433	      name: data.name || "?",
434	      country: data.country || "?",
435	      countryCN: countryCN(data.country),
436	      stage,
437	      colKey: stageColKey(stage),
438	      tier,
439	      urgencyKey,
440	      factors,
