function makeBadge(f, daysSince, paymentConfirmed) {
  const code = (f.factor || "").split("(")[0].trim();
  const days = f.days || daysSince || 0;
  const isObserve = !!f.observeMode;
  const isHigh = f.priority === "high";
  const isDoudi = (f.factor || "").includes("兜底");

  switch (code) {
    case "S3 该推进了":
      if (days <= 3) return `未回${days}d`;
      if (days <= 7) return `沉默${days}d`;
      return `推进${days}d`;
    case "S4 该催款了":
      if (isObserve) return "催款观察";
      if (f.degraded) return "降级";
      if (f.overdue) return `补催${days}d`;
      return `催款${days}d`;
    case "S1 该深挖需求了":
      if (isDoudi) return `兜底${days}d`;
      return `深挖${days}d`;
    case "S2 该追问了":
      return `追问${days}d`;
    case "S5a 该更新进度了":
      if (isHigh) return "超期!";
      if (!paymentConfirmed) return "待核实";
      return `进度${days}d`;
    case "S6 该更新物流了":
      return "物流";
    case "S7a 该回访了":
      return "回访";
    case "S7b 该推返单了":
      return "返单";
    case "S8 该收尾了":
      return "收尾";
    case "S9 该接触了":
      return "接触";
    default:
      return "待办";
  }
}

