</div>

<script>
var CARDS = ${JSON.stringify(cards)};

function openModal(cid) {
  var c = CARDS.find(function(x){ return x.cid === cid; });
  if (!c) return;
  var h = '';
  h += '<div class="modal-header"><h2>' + esc(c.name) + '</h2><button class="modal-close" onclick="closeModal()">✕</button></div>';
  h += '<div class="modal-body">';

  // Frontmatter
  h += '<div class="fm-grid">';
  var fields = [
    ['国家', c.countryCN || c.country],
    ['阶段', c.stage],
    ['等级', c.tier + '级'],
    ['最后联系', c.daysSince !== null ? c.daysSince + '天前' : '?']
  ];
  for (var i = 0; i < fields.length; i++) {
    h += '<div class="fm-item"><div class="fm-label">' + fields[i][0] + '</div><div class="fm-value">' + esc(String(fields[i][1])) + '</div></div>';
  }
  if (c.firstContact) {
    h += '<div class="fm-item"><div class="fm-label">首次联系</div><div class="fm-value">' + c.firstContact + '</div></div>';
  }
  h += '</div>';

  // Driver factors (服务端预生成)
  if (c.richDrivers && c.richDrivers.length) {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="driver-list">';
    for (var j = 0; j < c.richDrivers.length; j++) {
      var dr = c.richDrivers[j];
      var cls = dr.level === 'red' ? 'driver-item-red' : 'driver-item-yellow';
      var icon = dr.level === 'red' ? '🔴' : '🟡';
      h += '<div class="driver-item ' + cls + '"><span class="driver-icon">' + icon + '</span><div><strong>' + esc(dr.title) + '</strong><div style="color:#999;font-size:0.85em;margin-top:2px;">' + esc(dr.detail) + '</div></div></div>';
    }
    h += '</div></div>';
  } else if (c.urgencyKey === 'red') {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">⚠️ 该客户标记为需立即处理（状态卡热度=NOW），但未命中因子节奏天。请检查状态卡确认紧急原因。</div></div>';
  } else if (c.urgencyKey === 'yellow') {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">📌 该客户标记为需关注（状态卡热度=NOW/SOON），但未命中因子节奏天。可能是刚联系过或等待客户行动中。</div></div>';
  } else if (c.urgencyKey !== 'frozen') {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">无活跃因子。该客户在正常流转中，暂无行动信号。</div></div>';
  }

  // Chat lines (中文摘要)
  if (c.chatLinesCN && c.chatLinesCN.length) {
    h += '<div class="section"><div class="section-title">💬 聊到哪了</div><div class="chat-snippet">';
    for (var k = 0; k < c.chatLinesCN.length; k++) {
      var cl = c.chatLinesCN[k];
      var whoClass = cl.who === '我方' ? 'chat-who-me' : 'chat-who-cust';
      h += '<div class="chat-line"><span class="chat-who ' + whoClass + '">' + esc(cl.who) + '</span><span class="chat-time">' + esc(cl.time) + '</span>' + esc(cl.action) + '</div>';
    }
    h += '</div></div>';
  } else if (c.chatLines && c.chatLines.length) {
    // 降级：无中文摘要时显示原文
    h += '<div class="section"><div class="section-title">💬 聊到哪了</div><div class="chat-snippet">';
    for (var k = 0; k < c.chatLines.length; k++) {
      var cl2 = c.chatLines[k];
      var whoClass2 = cl2.who === 'me' ? 'chat-who-me' : 'chat-who-cust';
      h += '<div class="chat-line"><span class="chat-who ' + whoClass2 + '">' + (cl2.who === 'me' ? '我' : '客') + '</span><span class="chat-time">' + cl2.time + '</span>' + esc(cl2.text) + '</div>';
    }
    h += '</div></div>';
  }

  // Key numbers
  if (c.keyNums && c.keyNums.length) {
    h += '<div class="section"><div class="section-title">🔢 关键数字</div>';
    for (var m = 0; m < c.keyNums.length; m++) {
      h += '<div class="key-num">' + esc(c.keyNums[m]) + '</div>';
    }
    h += '</div>';
  }

  // Next step
  if (c.nextStep) {
    h += '<div class="section"><div class="section-title">→ 下一步</div><div style="font-size:0.9em;line-height:1.7;white-space:pre-line">' + esc(c.nextStep) + '</div></div>';
  }

  if (!c.hasBrief && c.urgencyKey !== 'frozen') {
    h += '<div class="info-note">📝 暂无状态卡。运行 /okki 深度分析创建详细档案。</div>';
  }

  h += '</div>';
  h += '<div class="modal-footer"><button class="btn btn-primary">✏️ 起草回复</button><button class="btn">🔍 深度分析</button><button class="btn">✅ 标记已处理</button></div>';

  document.getElementById('modal').innerHTML = h;
  document.getElementById('overlay').classList.add('show');
}

function closeModal() {
  document.getElementById('overlay').classList.remove('show');
}

function esc(s) {
  if (typeof s !== 'string') return String(s);
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

document.addEventListener('keydown', function(e) { if (e.key === 'Escape') closeModal(); });
</script>

</body>
</html>`;

  return html;
}

// ═══════════════════════════════════════════════
// Markdown 表格（兼容旧模式）
// ═══════════════════════════════════════════════

function renderMarkdown(cards) {
  const active = cards.filter(c => c.urgencyKey !== "frozen");
  const counts = {};
  for (const c of cards) counts[c.urgencyKey] = (counts[c.urgencyKey] || 0) + 1;

  let md = `# OKKI 客户看板\n\n`;
  md += `> ${TODAY} | 🔴需立即处理:${counts.red||0} 🟡需定时关注:${counts.yellow||0} ⚪正常:${counts.grey||0} ❄️冷冻:${counts.frozen||0}\n\n`;
  md += `| 客户 | 国家 | 等级 | 阶段 | 最后联系 | 驱动因子 | 下一步 |\n`;
  md += `|------|------|:---:|------|----------|----------|--------|\n`;

  let lastU = "";
  for (const u of ["red", "yellow", "grey"]) {
    for (const c of active) {
      if (c.urgencyKey !== u) continue;
      if (c.urgencyKey !== lastU) {
        lastU = c.urgencyKey;
        const label = URGENCY[u.toUpperCase()] ? URGENCY[u.toUpperCase()].label : u;
        md += `| **── ${label} ──** | | | | | | |\n`;
      }
      const factorNames = c.richDrivers.map(d => d.title.replace(/——.*$/, "")).join(" · ") || "—";
      const daysStr = c.daysSince !== null ? `${c.daysSince}天前` : "?";
      md += `| ${c.name} | ${c.countryCN} | ${c.tier} | ${c.stage} | ${daysStr} | ${factorNames} | ${(c.nextStep || "—").replace(/\n/g, " ")} |\n`;
    }
  }
  return md;
}

// ═══════════════════════════════════════════════
// 旧版 HTML 表格（--html 兼容）
// ═══════════════════════════════════════════════

function renderHTMLTable(cards) {
  const active = cards.filter(c => c.urgencyKey !== "frozen");

  let html = `<!DOCTYPE html>
<html lang="zh-CN">
<head><meta charset="UTF-8"><title>OKKI 客户看板 — ${TODAY}</title>
<style>
  body { font-family: -apple-system, sans-serif; margin: 20px; color: #333; }
  table { border-collapse: collapse; width: 100%; font-size: 0.9em; }
  th { background: #f5f5f5; padding: 10px 8px; text-align: left; border-bottom: 2px solid #ddd; }
  td { padding: 8px; border-bottom: 1px solid #eee; vertical-align: top; }
  .heat-red { color: #d32f2f; font-weight: bold; }
  .heat-yellow { color: #f57c00; }
  .heat-grey { color: #999; }
  .section-row td { background: #f0f0f0; font-weight: bold; padding: 6px 8px; font-size: 0.85em; }
</style></head><body>
<h1>OKKI 客户看板</h1><p>${TODAY}</p>
<table><thead><tr><th>客户</th><th>国家</th><th>等级</th><th>阶段</th><th>最后联系</th><th>驱动因子</th><th>下一步</th></tr></thead><tbody>`;

  let lastU = "";
  for (const c of active) {
    if (c.urgencyKey !== lastU) {
      lastU = c.urgencyKey;
      html += `<tr class="section-row"><td colspan="7">── ${URGENCY[c.urgencyKey.toUpperCase()]?.label || c.urgencyKey} ──</td></tr>\n`;
    }
    const cls = `heat-${c.urgencyKey}`;
    const factors = c.richDrivers.map(d => d.title).join(" · ") || "—";
    html += `<tr>
  <td>${esc(c.name)}</td><td>${c.countryCN}</td><td>${c.tier}</td><td>${c.stage}</td>
  <td>${c.daysSince !== null ? c.daysSince + "天前" : "?"}</td>
  <td>${esc(factors)}</td><td>${esc((c.nextStep || "—").replace(/\n/g, " "))}</td></tr>\n`;
  }

  html += `</tbody></table></body></html>`;
  return html;
}

function esc(s) {
  if (typeof s !== "string") return String(s);
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
}

// ═══════════════════════════════════════════════
// main
// ═══════════════════════════════════════════════

function main() {
  const cards = buildCustomerCards();
  if (!cards) process.exit(1);

  const counts = {};
  for (const c of cards) counts[c.urgencyKey] = (counts[c.urgencyKey] || 0) + 1;

  let output;
  if (mdMode) {
    output = renderMarkdown(cards);
  } else if (htmlTableMode) {
    output = renderHTMLTable(cards);
  } else {
    output = renderMatrixHTML(cards);
  }

  const dest = outFile || (mdMode || htmlTableMode ? null : path.join(OUTPUT_DIR, "dashboard.html"));

  if (dest) {
    fs.writeFileSync(dest, output, "utf-8");
    console.log(`✅ 看板已生成: ${dest}`);
  } else {
    console.log(output);
  }

  console.error(`\n── OKKI 看板 ${TODAY} ──`);
  console.error(`🔴 需立即处理: ${counts.red || 0}人`);
  console.error(`🟡 需定时关注: ${counts.yellow || 0}人`);
  console.error(`⚪ 正常流转:   ${counts.grey || 0}人`);
  console.error(`❄️ 冷冻:       ${counts.frozen || 0}人`);
  console.error(`📊 总计:       ${cards.length}人`);
}

main();

