434	/** 计算SOON因子命中 */
435	function computeFactors(stage, bl, meta, daysSinceMsg, lastSenderIsMe) {
436	  const factors = [];
437	  const t = TODAY_DATE;
438	
439	  switch (stage) {
440	    case '需求探索': {
441	      const d = parseDate(bl.S1);
442	      if (!d) break;
443	      const days = daysBetween(d, t);
444	      if (days < 1) break;
445	      const hitIdx = rhythmHit(days, RHYTHM.S1, 'S1');
446	      if (hitIdx >= 0) {
447	        const rhythmDay = RHYTHM.S1[hitIdx];
448	        factors.push({ factor: 'S1 该深挖需求了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S1 });
449	      }
450	      break;
451	    }
452	    case '报价已发': {
453	      const d = parseDate(bl.S2);
454	      if (!d) break;
455	      const days = daysBetween(d, t);
456	      if (days < 1) break;
457	      const hitIdx = rhythmHit(days, RHYTHM.S2, 'S2');
458	      if (hitIdx >= 0) {
459	        const rhythmDay = RHYTHM.S2[hitIdx];
460	        factors.push({ factor: 'S2 该追问了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S2 });
461	      }
462	      break;
463	    }
464	    case '谈判中': {
465	      const d = parseDate(bl.S3);
466	      if (!d) break;
467	      const days = daysBetween(d, t);
468	      if (days < 1) break;
469	      const hitIdx = rhythmHit(days, RHYTHM.S3, 'S3');
470	      if (hitIdx >= 0) {
471	        const rhythmDay = RHYTHM.S3[hitIdx];
472	        factors.push({ factor: 'S3 该推进了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S3 });
473	      }
474	      break;
475	    }
476	    case '待付款': {
477	      const d = parseDate(bl.S4);
478	      if (!d) break;
479	      const days = daysBetween(d, t);
480	      if (days < 1) break;
481	      const hitIdx = rhythmHit(days, RHYTHM.S4, 'S4');
482	      if (hitIdx >= 0) {
483	        const rhythmDay = RHYTHM.S4[hitIdx];
484	        const lastIdx = RHYTHM.S4.length - 1;
485	        const isDegraded = (hitIdx === lastIdx && days > rhythmDay + 1);
486	        factors.push({ factor: 'S4 该催款了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S4, degraded: isDegraded });
487	      }
488	      break;
489	    }
490	    case '待发货': {
491	      // S5a: 双基线
492	      if (bl.S5a_A) {
493	        const daysA = daysBetween(parseDate(bl.S5a_A), t);
494	        const interval = s5aInterval(meta);
495	        if (daysA >= interval && daysA % interval === 0) {
496	          factors.push({ factor: 'S5a 该更新进度了', days: daysA, interval, baseline: bl.S5a_A, priority: 'normal' });
497	        }
498	      }
499	      // S5a-B: 承诺发货日超期检查（需外部填写 committed_ship_date）
500	      if (meta.committed_ship_date && bl.S5a_A) {
501	        const shipDate = parseDate(meta.committed_ship_date);
502	        if (shipDate && t > shipDate) {
503	          const overdue = daysBetween(shipDate, t);
504	          factors.push({ factor: 'S5a 该更新进度了(超期)', days: overdue, priority: 'high', reason: '超承诺发货日' });
505	        }
506	      }
507	      break;
508	    }
509	    case '已发货/在途': {
510	      const d = parseDate(bl.S6);
511	      if (!d) break;
512	      const days = daysBetween(d, t);
513	      const interval = s6Interval(meta);
514	      if (days >= 1 && days % interval === 0) {
515	        factors.push({ factor: 'S6 该更新物流了', days, rhythmDay: days, baseline: bl.S6, interval });
516	      }
517	      break;
518	    }
519	    case '已签收':
520	    case '待返单': {
521	      if (bl.S7) {
522	        const d = parseDate(bl.S7);
523	        if (d) {
524	          const days = daysBetween(d, t);
525	          if (days >= 1) {
526	            const hitIdx = rhythmHit(days, RHYTHM.S7, 'S7');
527	            if (hitIdx >= 0) {
528	              const rhythmDay = RHYTHM.S7[hitIdx];
529	              factors.push({ factor: 'S7 该联系了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S7 });
530	            }
531	          }
532	        }
533	      }
534	      break;
535	    }
536	    case '售后': {
537	      const d = parseDate(bl.S8);
538	      if (!d) break;
539	      const days = daysBetween(d, t);
540	      if (days < 1) break;
541	      const hitIdx = rhythmHit(days, RHYTHM.S8, 'S8');
542	      if (hitIdx >= 0) {
543	        const rhythmDay = RHYTHM.S8[hitIdx];
544	        factors.push({ factor: 'S8 该收尾了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S8 });
545	      }
546	      break;
547	    }
548	  }
549	
550	  return factors;
551	}
