/**
 * init_factor_baselines.js — factor_baselines.json 初始化 + SOON因子计算 + 冷层分层
 *
 * 数据源:
 *   - data/s3_ai_judgments.json   (AI精判阶段+等级+优先级, 496人)
 *   - data/heat_classification.json (消息元数据: lastMsgTime/lastSender, 466人)
 *
 * 输出:
 *   - output/factor_baselines.json
 *   - output/soon_layer_cards.json
 *   - output/cold_layer_stratification.json
 *   - output/stage_corrections.json
 *   - output/init_report_*.md
 */

const fs = require('fs');
const path = require('path');

const TODAY_DATE = new Date();
const TODAY = TODAY_DATE.toISOString().slice(0, 10);

// ============ SOON因子节奏表 (V4 定稿) ============
// 绝对天数制

const RHYTHM = {
  S1:  [1, 2, 3, 5, 7, 9, 15, 30],           // 需求探索（终点=30d=流转阈值）
  S2_sample: [1, 3, 5, 15],                   // 样品报价（终点=15d=流转阈值）
  S2_bulk:   [1, 3, 5, 15, 30],               // 大货报价（终点=30d=流转阈值）
  S3:  [1, 3, 5, 7, 15, 30],                  // 谈判中（终点=30d）
  S4:  [1, 3, 5, 7],                           // 待付款（之后每7天观察）
  S7:  [0, 3, 5, 10, 15, 30, 45, 60, 75, 90], // 已签收/待返单
  S8:  [1, 2, 3, 5, 7, 15, 30],               // 售后（终点=Day45兜底）
};

// 终止型因子（终点±1天后不再提醒）
const TERMINAL_FACTORS = new Set(['S1', 'S2', 'S7', 'S8']);

// 活肤阶段（出现在矩阵中）
const ACTIVE_STAGES = new Set([
  '需求探索', '报价已发', '谈判中', '待付款', '待发货', '已发货/在途', '已签收', '售后', '待返单'
]);

// 冷层阶段
const COLD_STAGES = new Set(['搁置', '未成交']);

// ============ 辅助函数 ============

function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

function daysBetween(d1, d2) {
  return Math.floor((d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24));
}

/** 判定节奏命中：rhythmArr 为绝对天数。最后一个节点后有1天容差，终止型因子终点±1天就停 */
function rhythmHit(days, rhythmArr, factorCode) {
  const isTerminal = factorCode && TERMINAL_FACTORS.has(factorCode);
  for (let i = rhythmArr.length - 1; i >= 0; i--) {
    const targetDay = rhythmArr[i];
    if (days < targetDay) continue;
    if (isTerminal) return (days <= targetDay + 1) ? i : -1;
    if (i === rhythmArr.length - 1) return (days <= targetDay + 1) ? i : -1;
    if (days <= targetDay + 1) return i;
  }
  return -1;
}

/** S5a 双基线间隔 */
function s5aInterval(meta) {
  if (meta.customer_type === '样品单') return 3;
  if (!meta.transit_days) return 7;
  const interval = Math.round(meta.transit_days / 5);
  return Math.max(3, Math.min(10, interval));
}

/** S6 间隔: 时效÷N */
function s6Interval(meta) {
  const transitDays = meta.transit_days || 25;
  const N = { S: 6, A: 6, B: 5, C: 5, D: 4 }[meta.customer_tier] || 5;
  const interval = Math.round(transitDays / N);
  return Math.max(2, Math.min(15, interval));
}

/** 国家是否非洲/中东 */
function isAfricaOrMiddleEast(country) {
  const africaME = ['SD','EG','CD','ZM','CI','SA','AE','IQ','GH','NG','KE','TZ','UG','ET','CM','SN','ML','BF','BJ','TG','LY','MA','DZ','TN','KW','QA','BH','OM','JO','LB','YE','SY','PS','CG','GA','MR','SO'];
  return africaME.includes((country || '').toUpperCase());
}

/** 加载订单数据 */
function loadOrderMap() {
  const map = new Map();
  try {
    const ordersPath = path.join(__dirname, '..', 'data', 'orders_latest.json');
    if (fs.existsSync(ordersPath)) {
      const orders = JSON.parse(fs.readFileSync(ordersPath, 'utf-8'));
      for (const o of orders.orders || []) {
        const nameKey = (o.customer || '').toLowerCase().trim();
        if (nameKey) map.set(nameKey, o);
      }
    }
  } catch (e) { /* ignore */ }
  return map;
}

/** 订单数据校正阶段 */
function correctStageByOrder(name, currentStage, orderMap) {
  const nameKey = (name || '').toLowerCase().trim();
  const order = orderMap.get(nameKey);
  if (!order) return { stage: currentStage, orderStatus: null, paymentConfirmed: false };

  const st = order.status;
  if (currentStage === '待发货') {
    if (st === '待收款') return { stage: '待付款', orderStatus: st, paymentConfirmed: false };
    if (st === '已发货') return { stage: '已发货/在途', orderStatus: st, paymentConfirmed: true };
    if (st === '交易成功') return { stage: '已签收', orderStatus: st, paymentConfirmed: true };
    if (st === '交易取消') return { stage: '未成交', orderStatus: st, paymentConfirmed: false };
    if (st === '待发货') return { stage: currentStage, orderStatus: st, paymentConfirmed: true };
    return { stage: currentStage, orderStatus: st, paymentConfirmed: false };
  }
  if (currentStage === '待付款') {
    if (st === '已发货') return { stage: '已发货/在途', orderStatus: st, paymentConfirmed: true };
    if (st === '交易成功') return { stage: '已签收', orderStatus: st, paymentConfirmed: true };
    if (st === '交易取消') return { stage: '未成交', orderStatus: st, paymentConfirmed: false };
    if (st === '待收款') return { stage: currentStage, orderStatus: st, paymentConfirmed: false };
    return { stage: currentStage, orderStatus: st, paymentConfirmed: st === '待发货' };
  }
  return { stage: currentStage, orderStatus: st, paymentConfirmed: (st === '待发货' || st === '已发货' || st === '交易成功') };
}

// ============ 因子计算 ============

function computeFactors(stage, bl, meta, daysSinceMsg, lastSenderIsMe) {
  const factors = [];
  const t = TODAY_DATE;

  switch (stage) {
    case '需求探索': {
      const d = parseDate(bl.S1);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const hitIdx = rhythmHit(days, RHYTHM.S1, 'S1');
      if (hitIdx >= 0) {
        factors.push({ factor: 'S1 该深挖需求了', days, rhythmDay: RHYTHM.S1[hitIdx], intervalIndex: hitIdx, baseline: bl.S1 });
      }
      break;
    }
    case '报价已发': {
      const d = parseDate(bl.S2);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const rhythmArr = meta.customer_type === '样品单' ? RHYTHM.S2_sample : RHYTHM.S2_bulk;
      const hitIdx = rhythmHit(days, rhythmArr, 'S2');
      if (hitIdx >= 0) {
        factors.push({ factor: 'S2 该追问了', days, rhythmDay: rhythmArr[hitIdx], intervalIndex: hitIdx, baseline: bl.S2, subtype: meta.customer_type });
      }
      break;
    }
    case '谈判中': {
      const d = parseDate(bl.S3);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const hitIdx = rhythmHit(days, RHYTHM.S3, 'S3');
      if (hitIdx >= 0) {
        factors.push({ factor: 'S3 该推进了', days, rhythmDay: RHYTHM.S3[hitIdx], intervalIndex: hitIdx, baseline: bl.S3 });
      }
      break;
    }
    case '待付款': {
      const d = parseDate(bl.S4);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const hitIdx = rhythmHit(days, RHYTHM.S4, 'S4');
      if (hitIdx >= 0) {
        const rhythmDay = RHYTHM.S4[hitIdx];
        const lastIdx = RHYTHM.S4.length - 1;
        const isDegraded = (hitIdx === lastIdx && days > rhythmDay + 1);
        factors.push({ factor: 'S4 该催款了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S4, degraded: isDegraded });
      } else if (days > 7) {
        // Day 7后每7天观察提醒
        const obsWeeks = Math.floor(days / 7);
        if (days % 7 <= 1) {
          factors.push({ factor: 'S4 该催款了(观察)', days, observeMode: true, weekIndex: obsWeeks, baseline: bl.S4 });
        }
      }
      break;
    }
    case '待发货': {
      if (bl.S5a_A) {
        const daysA = daysBetween(parseDate(bl.S5a_A), t);
        const interval = s5aInterval(meta);
        if (daysA >= interval && daysA % interval <= 1) {
          factors.push({ factor: 'S5a 该更新进度了', days: daysA, interval, baseline: bl.S5a_A, priority: 'normal' });
        }
      }
      if (meta.committed_ship_date && bl.S5a_A) {
        const shipDate = parseDate(meta.committed_ship_date);
        if (shipDate && t > shipDate) {
          const overdue = daysBetween(shipDate, t);
          factors.push({ factor: 'S5a 该更新进度了(超期)', days: overdue, priority: 'high', reason: '超承诺发货日' });
        }
      }
      break;
    }
    case '已发货/在途': {
      const d = parseDate(bl.S6);
      if (!d) break;
      const days = daysBetween(d, t);
      const interval = s6Interval(meta);
      if (days >= 1 && days % interval <= 1) {
        factors.push({ factor: 'S6 该更新物流了', days, rhythmDay: days, baseline: bl.S6, interval });
      }
      break;
    }
    case '已签收':
    case '待返单': {
      if (bl.S7) {
        const d = parseDate(bl.S7);
        if (d) {
          const days = daysBetween(d, t);
          if (days >= 0) {
            const hitIdx = rhythmHit(days, RHYTHM.S7, 'S7');
            if (hitIdx >= 0) {
              factors.push({ factor: 'S7 该联系了', days, rhythmDay: RHYTHM.S7[hitIdx], intervalIndex: hitIdx, baseline: bl.S7 });
            }
          }
        }
      }
      break;
    }
    case '售后': {
      const d = parseDate(bl.S8);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const hitIdx = rhythmHit(days, RHYTHM.S8, 'S8');
      if (hitIdx >= 0) {
        factors.push({ factor: 'S8 该收尾了', days, rhythmDay: RHYTHM.S8[hitIdx], intervalIndex: hitIdx, baseline: bl.S8 });
      }
      break;
    }
  }

  return factors;
}

function summarizeFactors(soonCustomers) {
  const factorCounts = {};
  for (const c of soonCustomers) {
    for (const f of c.factors) {
      const key = f.factor.split('(')[0].trim();
      factorCounts[key] = (factorCounts[key] || 0) + 1;
    }
  }
  return factorCounts;
}

// ============ 主流程 ============

function checkFreshness() {
  const p = path.join(__dirname, '..', 'data', '.last_sync.json');
  if (!fs.existsSync(p)) {
    console.log('⚠️  无同步记录，建议先运行 sync_okki.js');
    return;
  }
  const { date, count } = JSON.parse(fs.readFileSync(p, 'utf-8'));
  const daysAgo = daysBetween(new Date(date), TODAY_DATE);
  if (daysAgo > 0) console.log(`⚠️  数据 ${daysAgo} 天前同步（${date}），有疑问请先 sync`);
  else console.log(`✅ 今日已同步 ${count} 会话`);
}

function main() {
  checkFreshness();

  // ── 读取双数据源 ──
  const s3Path = path.join(__dirname, '..', 'data', 's3_ai_judgments.json');
  const heatPath = path.join(__dirname, '..', 'data', 'heat_classification.json');

  if (!fs.existsSync(s3Path)) {
    console.error('s3_ai_judgments.json 不存在，请先运行 AI 分类流程');
    process.exit(1);
  }
  if (!fs.existsSync(heatPath)) {
    console.error('heat_classification.json 不存在');
    process.exit(1);
  }

  const s3Data = JSON.parse(fs.readFileSync(s3Path, 'utf-8'));
  const heatData = JSON.parse(fs.readFileSync(heatPath, 'utf-8'));

  // 构建 s3 查找表: cid → { stage, grade, priority }
  const s3Map = new Map();
  for (const c of s3Data) {
    s3Map.set(c.cid, { stage: c.stage, grade: c.grade, priority: c.priority });
  }

  console.log(`s3_ai_judgments: ${s3Data.length} 人`);
  console.log(`heat_classification: ${heatData.results.length} 人`);

  // ── 合并数据源 ──
  const orderMap = loadOrderMap();
  const baselines = {};
  const stageStats = {};
  const stageCorrections = [];
  const soonCustomers = [];
  const coldCustomers = [];
  const frozenLayers = {
    highValue: [],
    deepFrozen: [],
    normal: [],
    neverDeal: [],
  };

  // 处理 heat_classification 中的客户（有消息数据）
  for (const c of heatData.results) {
    const s3Info = s3Map.get(c.cid);
    let aiStage = s3Info ? s3Info.stage : null;
    const aiGrade = s3Info ? s3Info.grade : 'C';
    const aiPriority = s3Info ? s3Info.priority : 'idle';

    // 搁置/未成交 → 冷层
    if (aiStage && COLD_STAGES.has(aiStage)) {
      aiStage = null;
    }

    // 订单交叉验证
    let newStage = aiStage;
    let orderCorrection = { stage: aiStage, orderStatus: null, paymentConfirmed: false };
    if (aiStage) {
      orderCorrection = correctStageByOrder(c.name, aiStage, orderMap);
      newStage = orderCorrection.stage;
      if (newStage !== aiStage) {
        stageCorrections.push({
          cid: c.cid, name: c.name,
          oldStage: aiStage,
          newStage,
          reason: `订单状态=${orderCorrection.orderStatus}`,
        });
      }
    }

    // 统计
    const displayStage = newStage || '冷层';
    stageStats[displayStage] = (stageStats[displayStage] || 0) + 1;

    // meta
    const lastMsgDate = parseDate(c.lastMsgTime);
    const daysSinceMsg = lastMsgDate ? daysBetween(lastMsgDate, TODAY_DATE) : 999;
    const lastSenderIsMe = c.lastSender === '我';

    const meta = {
      transit_days: null,
      customer_tier: aiGrade,
      _tier_source: 's3_ai_judgment',
      committed_ship_date: null,
      has_address: null,
      customer_type: (newStage === '样品阶段') ? '样品单' : '大货',
      repurchase_cycle_days: null,
      target_market: isAfricaOrMiddleEast(c.country) ? 'africa_me' : 'other',
      s8_boundary_checked: false,
      _payment_confirmed: orderCorrection.paymentConfirmed,
      _order_status: orderCorrection.orderStatus,
      _ai_priority: aiPriority,
    };

    // baselines
    const bl = { S1: null, S2: null, S3: null, S4: null, S5a_A: null, S5a_B: null, S6: null, S7: null, S8: null };

    if (newStage && ACTIVE_STAGES.has(newStage)) {
      // 按阶段设基线
      switch (newStage) {
        case '需求探索':
          if (lastSenderIsMe) bl.S1 = c.lastMsgTime;
          break;
        case '报价已发':
          bl.S2 = c.lastMsgTime;
          break;
        case '谈判中':
          bl.S3 = c.lastMsgTime;
          break;
        case '待付款':
          bl.S4 = c.lastMsgTime;
          break;
        case '待发货':
          if (lastSenderIsMe) bl.S5a_A = c.lastMsgTime;
          break;
        case '已发货/在途':
          bl.S6 = c.lastMsgTime;
          meta.transit_days = isAfricaOrMiddleEast(c.country) ? 30 : 25;
          break;
        case '已签收':
          bl.S7 = c.lastMsgTime;
          break;
        case '售后':
          if (lastSenderIsMe) bl.S8 = c.lastMsgTime;
          break;
        case '待返单':
          bl.S7 = c.lastMsgTime;
          break;
      }

      // 计算因子命中
      const factors = computeFactors(newStage, bl, meta, daysSinceMsg, lastSenderIsMe);

      baselines[c.cid] = {
        name: c.name,
        country: c.country,
        stage: newStage,
        stage_updated: null,
        baselines: bl,
        meta,
      };

      if (factors.length > 0) {
        soonCustomers.push({
          cid: c.cid,
          name: c.name,
          country: c.country,
          stage: newStage,
          heat: aiPriority === 'now' ? 'NOW' : aiPriority === 'soon' ? 'SOON' : 'IDLE',
          tier: aiGrade,
          daysSinceLastContact: c.daysSinceLastContact,
          factors,
        });
      }
    } else {
      // 冷层
      baselines[c.cid] = {
        name: c.name,
        country: c.country,
        stage: null,
        stage_updated: null,
        baselines: bl,
        meta,
      };
      coldCustomers.push({
        cid: c.cid,
        name: c.name,
        country: c.country,
        daysSinceLastContact: c.daysSinceLastContact,
        tier: aiGrade,
        lastMsgTime: c.lastMsgTime,
        lastSender: c.lastSender,
      });
    }
  }

  // 处理仅在 s3 中的客户（无消息数据，默认冷层）
  for (const c of s3Data) {
    if (baselines[c.cid]) continue; // 已处理
